//! TPE ParzenEstimator log_pdf cross-validation tests.
//!
//! Golden values generated by `tests/golden_tpe_split.py` using Python optuna.
//! Tests cover: Float, LogFloat, Integer, Categorical, single-observation edge cases.

use indexmap::IndexMap;
use std::collections::HashMap;

use optuna_rs::distributions::*;
use optuna_rs::samplers::tpe::parzen_estimator::{ParzenEstimator, ParzenEstimatorParameters};

const TOL: f64 = 1e-8;

fn assert_close(actual: f64, expected: f64, tol: f64, msg: &str) {
    if expected.is_infinite() {
        assert!(
            actual.is_infinite() && actual.signum() == expected.signum(),
            "{msg}: expected {expected}, got {actual}"
        );
        return;
    }
    if expected.is_nan() {
        assert!(actual.is_nan(), "{msg}: expected NaN, got {actual}");
        return;
    }
    let diff = (actual - expected).abs();
    let denom = expected.abs().max(1.0);
    assert!(
        diff / denom < tol,
        "{msg}: expected {expected}, got {actual}, rel_diff={:.2e}",
        diff / denom
    );
}

fn assert_vec_close(actual: &[f64], expected: &[f64], tol: f64, msg: &str) {
    assert_eq!(
        actual.len(),
        expected.len(),
        "{msg}: length {}, expected {}",
        actual.len(),
        expected.len()
    );
    for (i, (&a, &e)) in actual.iter().zip(expected.iter()).enumerate() {
        assert_close(a, e, tol, &format!("{msg}[{i}]"));
    }
}

fn default_pe_params() -> ParzenEstimatorParameters {
    ParzenEstimatorParameters::default()
}

// ═══════════════════════════════════════════════════════════════════════════
//  1. Float log_pdf — 3 observations on [0, 10]
//     Python: FloatDistribution(0.0, 10.0), obs=[2,5,8], prior_weight=1.0
// ═══════════════════════════════════════════════════════════════════════════

#[test]
fn cv_logpdf_float_3obs_python_golden() {
    let mut ss = IndexMap::new();
    ss.insert(
        "x".to_string(),
        Distribution::FloatDistribution(FloatDistribution::new(0.0, 10.0, false, None).unwrap()),
    );
    let mut obs = HashMap::new();
    obs.insert("x".to_string(), vec![2.0, 5.0, 8.0]);
    let pe = ParzenEstimator::new(&obs, &ss, &default_pe_params(), None, None);

    // Python golden: mixture weights = [0.25, 0.25, 0.25, 0.25]
    let expected_weights = [0.25, 0.25, 0.25, 0.25];
    assert_vec_close(pe.weights(), &expected_weights, TOL, "float_3obs_weights");

    // Python golden: mus=[2,5,8,5], sigmas=[3,3,3,10]
    let (mus, sigmas, low, high) = pe.numerical_kernels("x").unwrap();
    assert_vec_close(&mus, &[2.0, 5.0, 8.0, 5.0], TOL, "float_3obs_mus");
    assert_vec_close(&sigmas, &[3.0, 3.0, 3.0, 10.0], TOL, "float_3obs_sigmas");
    assert_close(low, 0.0, TOL, "float_3obs_low");
    assert_close(high, 10.0, TOL, "float_3obs_high");

    // Python golden log_pdf values
    let test_points = vec![0.0, 1.0, 2.0, 3.0, 5.0, 7.0, 8.0, 10.0];
    let expected_logpdf = [
        -2.670406218091419,
        -2.472407766398193,
        -2.323311754094648,
        -2.2219369245113163,
        -2.1453012481753575,
        -2.2219369245113163,
        -2.323311754094648,
        -2.670406218091419,
    ];

    let samples = HashMap::from([("x".to_string(), test_points)]);
    let rust_logpdf = pe.log_pdf(&samples);
    assert_vec_close(&rust_logpdf, &expected_logpdf, TOL, "float_3obs_logpdf");
}

// ═══════════════════════════════════════════════════════════════════════════
//  2. Float log_pdf — symmetry check
//     log_pdf(0) == log_pdf(10) and log_pdf(3) == log_pdf(7) due to
//     symmetric observations [2,5,8] on [0,10]
// ═══════════════════════════════════════════════════════════════════════════

#[test]
fn cv_logpdf_float_symmetry() {
    let mut ss = IndexMap::new();
    ss.insert(
        "x".to_string(),
        Distribution::FloatDistribution(FloatDistribution::new(0.0, 10.0, false, None).unwrap()),
    );
    let mut obs = HashMap::new();
    obs.insert("x".to_string(), vec![2.0, 5.0, 8.0]);
    let pe = ParzenEstimator::new(&obs, &ss, &default_pe_params(), None, None);

    let samples = HashMap::from([("x".to_string(), vec![0.0, 10.0, 3.0, 7.0])]);
    let logpdf = pe.log_pdf(&samples);
    // Due to symmetric obs: 0↔10, 3↔7
    assert_close(logpdf[0], logpdf[1], TOL, "symmetry 0↔10");
    assert_close(logpdf[2], logpdf[3], TOL, "symmetry 3↔7");
}

// ═══════════════════════════════════════════════════════════════════════════
//  3. Float log_pdf — single observation
//     Python: obs=[5.0], prior_weight=1.0 → weights=[0.5, 0.5]
// ═══════════════════════════════════════════════════════════════════════════

#[test]
fn cv_logpdf_float_single_obs_python_golden() {
    let mut ss = IndexMap::new();
    ss.insert(
        "x".to_string(),
        Distribution::FloatDistribution(FloatDistribution::new(0.0, 10.0, false, None).unwrap()),
    );
    let mut obs = HashMap::new();
    obs.insert("x".to_string(), vec![5.0]);
    let pe = ParzenEstimator::new(&obs, &ss, &default_pe_params(), None, None);

    // Python golden: weights=[0.5, 0.5]
    assert_vec_close(pe.weights(), &[0.5, 0.5], TOL, "single_obs_weights");

    // Python golden log_pdf at [3,5,7]
    let expected = [-2.2186836715753673, -2.110630488309263, -2.2186836715753673];
    let samples = HashMap::from([("x".to_string(), vec![3.0, 5.0, 7.0])]);
    let rust_logpdf = pe.log_pdf(&samples);
    assert_vec_close(&rust_logpdf, &expected, TOL, "single_obs_logpdf");

    // Symmetry: log_pdf(3) == log_pdf(7) since obs=[5] is symmetric
    assert_close(rust_logpdf[0], rust_logpdf[2], TOL, "single_obs_symmetry");
}

