    // Symmetry: log_pdf(0) == log_pdf(10), log_pdf(2) == log_pdf(8)
    assert_close(rust_logpdf[0], rust_logpdf[4], TOL, "int_symmetry_0_10");
    assert_close(rust_logpdf[1], rust_logpdf[3], TOL, "int_symmetry_2_8");
